func TestNetworkSim_MerkleSync(t *testing.T) {
	ns := NewNetworkSim(42)
	ns.AddNode("n1", 1)
	ns.AddNode("n2", 1)
	ns.GetStore("n1").Put("mk1", []byte("mv1"))
	ns.GetStore("n2").Put("mk2", []byte("mv2"))

	for i := 0; i < 20; i++ {
		ns.RunMerkleSyncRound()
		if ns.Converged() {
			return
		}
	}
	t.Fatal("merkle sync should achieve convergence")
}

func TestNetworkSim_MerkleSyncPropagatesDelete(t *testing.T) {
	ns := NewNetworkSim(42)
	ns.AddNode("n1", 1)
	ns.AddNode("n2", 1)

	ns.GetStore("n1").Put("deleted-key", []byte("value"))
	runMerkleRoundsUntil(t, ns, 10, ns.Converged)

	ns.GetStore("n1").Delete("deleted-key")
	runMerkleRoundsUntil(t, ns, 10, ns.Converged)

	for _, nodeID := range []string{"n1", "n2"} {
		if _, ok := ns.GetStore(nodeID).Get("deleted-key"); ok {
			t.Fatalf("%s still has deleted-key after merkle sync", nodeID)
		}
	}
	if ns.GetStore("n1").Hash() != ns.GetStore("n2").Hash() {
		t.Fatal("node hashes should match after merkle delete convergence")
	}
}

func TestNetworkSim_MerkleSyncBulkDeletesConvergeHash(t *testing.T) {
	ns := NewNetworkSim(99)
	nodeIDs := []string{"n0", "n1", "n2", "n3"}
	for _, nodeID := range nodeIDs {
		ns.AddNode(nodeID, 2)
	}

	for i := 0; i < 24; i++ {
		ns.GetStore("n0").Put(fmt.Sprintf("bulk-%02d", i), []byte(fmt.Sprintf("value-%02d", i)))
	}
	runMerkleRoundsUntil(t, ns, 100, ns.Converged)

	deleted := make(map[string]bool)
	for i := 0; i < 24; i += 2 {
		key := fmt.Sprintf("bulk-%02d", i)
		ns.GetStore("n0").Delete(key)
		deleted[key] = true
	}
	runMerkleRoundsUntil(t, ns, 150, ns.Converged)

	expectedHash := ns.GetStore(nodeIDs[0]).Hash()
	for _, nodeID := range nodeIDs {
		store := ns.GetStore(nodeID)
		if store.Hash() != expectedHash {
			t.Fatalf("%s hash differs after bulk merkle deletes", nodeID)
		}
		for key := range deleted {
			if _, ok := store.Get(key); ok {
				t.Fatalf("%s still has %s after bulk merkle deletes", nodeID, key)
			}
		}
		for i := 1; i < 24; i += 2 {
			key := fmt.Sprintf("bulk-%02d", i)
			if _, ok := store.Get(key); !ok {
				t.Fatalf("%s missing live key %s after bulk merkle deletes", nodeID, key)
			}
		}
	}
}

